{
  description = "Smart Contract Audit Swarm Environment";

  inputs = {
    nixpkgs.url = "github:NixOS/nixpkgs/nixos-unstable";
  };

  outputs = { self, nixpkgs }:
  let
    system = "x86_64-linux";
    pkgs = import nixpkgs { inherit system; };
  in {
    devShells.${system}.default = pkgs.mkShell {
      buildInputs = with pkgs; [
        python3
        python3Packages.pip
        python3Packages.virtualenv
        solc # Solc is required by Slither to compile contracts during analysis
      ];

      shellHook = ''
        export LD_LIBRARY_PATH="${pkgs.stdenv.cc.cc.lib}/lib:$LD_LIBRARY_PATH"
        if [ ! -d .venv ]; then
          python -m venv .venv
          source .venv/bin/activate
          # Slither is now handled by pip to bypass the Nixpkgs Sphinx breakage
          pip install slither-analyzer crewai langchain-community langchain-ollama
        else
          source .venv/bin/activate
        fi
        echo "Audit Swarm Environment Active."
      '';
    };
  };
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract VulnerableVault {
    mapping(address => uint256) public balances;

    function deposit() public payable {
        balances[msg.sender] += msg.value;
    }

    function withdraw() public {
        uint256 bal = balances[msg.sender];
        require(bal > 0, "Insufficient balance");

        // VULNERABILITY: External call made before state update
        (bool sent, ) = msg.sender.call{value: bal}("");
        require(sent, "Failed to send Ether");

        // State updated after the external call
        balances[msg.sender] = 0;
    }
}
